INSERT INTO `company_info` VALUES (1, '校园二手街', '校园二手街是一家面向学校的二手交易平台，主营小家电、日用百货、清洁收纳和健康生活类商品。', '坚持严选供应链、透明价格、快速履约和可追踪售后，让用户买得清楚、用得安心、协商有记录。', '400-800-2026', 'service@example.com', '北京信息科技大学', '', 'https://www.example.com', '周一至周日 09:00-21:00', '2026-06-04 16:41:11');
