INSERT INTO `news` VALUES (1, '售后协商服务增加换货和配件补发通道', '用户可在订单记录中选择退货、换货、补发配件或其他协商类型，处理结果可追踪。', '<p>为提升商品售后处理效率，优品生活将售后协商入口细分为退货、换货、补发配件和其他协商。用户登录后可在订单记录中选择具体诉求，并补充问题描述，后台客服根据订单状态统一处理。</p><figure><img src=\"https://images.unsplash.com/photo-1556745757-8d76bdb6984b?auto=format&fit=crop&w=1200&q=80\" alt=\"客服处理售后信息\"><figcaption>客服工作台集中查看订单、协商类型和用户说明。</figcaption></figure><h2>处理结果可追踪</h2><p>管理员处理后，用户可以在售后协商记录中查看状态和回复。对于配件缺失、运输破损等问题，平台会优先核对出库清单和商品批次，减少重复沟通。</p>', '客服中心', 'https://images.unsplash.com/photo-1556745757-8d76bdb6984b?auto=format&fit=crop&w=1200&q=80', '售后,换货,配件补发', '优品生活', 318, 100, 1, '2026-05-22 15:33:54', '2026-05-22 16:33:54');
INSERT INTO `news` VALUES (2, '厨房轻食新品体验日在旗舰展厅举行', '旗舰展厅围绕早餐、办公室午餐和露营轻食三个场景展示新品。', '<p>优品生活在旗舰展厅举办厨房轻食新品体验日，集中展示便携料理机、恒温电热饭盒和硅胶保鲜套装。现场围绕早餐准备、办公室午餐和露营轻食三个场景，邀请用户体验商品容量、清洗方式和携带便利性。</p><figure><img src=\"https://images.unsplash.com/photo-1556911220-bff31c812dba?auto=format&fit=crop&w=1200&q=80\" alt=\"厨房台面上的轻食商品\"><figcaption>新品体验区按家庭厨房和办公室午餐场景布置。</figcaption></figure><h2>反馈进入商品迭代</h2><p>体验日收集到的杯体重量、饭盒分区和刀头清洗建议，将进入下一批商品采购和质检清单。</p>', '品牌市场部', 'https://images.unsplash.com/photo-1556911220-bff31c812dba?auto=format&fit=crop&w=1200&q=80', '新品,体验日,厨房', '优品生活', 246, 95, 1, '2026-05-22 14:33:54', '2026-05-22 16:33:54');
INSERT INTO `news` VALUES (3, '上海仓配中心完成智能分拣升级', '上海仓配中心新增按订单类型、商品场景和售后优先级分流的作业线。', '<p>优品生活上海仓配中心完成智能分拣升级，新增按订单类型、商品温控需求和售后换货优先级进行分流的作业线。升级后，小家电、清洁护理和厨房轻食类商品可以在出库前完成批次复核、外观抽检和包装确认。</p><figure><img src=\"https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?auto=format&fit=crop&w=1200&q=80\" alt=\"仓配中心货架与分拣区域\"><figcaption>仓配中心通过分区货架和条码复核提升出库准确率。</figcaption></figure><h2>订单履约更透明</h2><p>系统会在订单生成后记录商品批次、出库状态和售后协商入口，便于用户和客服共同追踪。</p>', '仓配中心', 'https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?auto=format&fit=crop&w=1200&q=80', '仓配,履约,订单', '优品生活', 291, 90, 1, '2026-05-22 13:33:54', '2026-05-22 16:33:54');
INSERT INTO `news` VALUES (4, '春季生活小家电系列正式发布', '春季生活小家电系列覆盖早餐料理、随身饮水、空气净化和桌面收纳等高频场景。', '<p>优品生活发布春季生活小家电系列，覆盖早餐料理、随身饮水、空气净化和桌面收纳等高频场景。新品统一采用可追踪批次管理，商品详情页展示价格、库存、标签和售后入口。</p><figure><img src=\"https://images.unsplash.com/photo-1556742049-0cfed4f6a45d?auto=format&fit=crop&w=1200&q=80\" alt=\"新品陈列\"><figcaption>春季新品在商品详情页同步展示价格、库存与售后入口。</figcaption></figure>', '商品中心', 'https://images.unsplash.com/photo-1556742049-0cfed4f6a45d?auto=format&fit=crop&w=1200&q=80', '新品,小家电,春季上新', '优品生活', 208, 80, 1, '2026-05-21 16:33:54', '2026-05-22 16:33:54');
