INSERT INTO `product` VALUES (1, 'YP-CUP-450', '智能恒温杯', '316不锈钢内胆，触控温显，适合通勤、会议和长时间办公饮水。', '/uploads/051cf9e44acf4dde9e7a4c721d3caf4e.png', '健康家居', 2, '新品,保温,办公', 129.00, 159.00, 296, '个', 124, 420, '容量450ml，Type-C充电，杯盖显示实时水温。杯体采用双层真空结构，减少外壁烫手问题。', 1, 1, NULL, NULL, '2026-05-14 16:33:54', '2026-05-29 14:59:26', NULL, 0, NULL, NULL, NULL);
INSERT INTO `product` VALUES (2, 'YP-BLEND-300', '便携料理机', '轻量杯体与安全锁结构，适合果汁、奶昔、辅食和健身餐制作。', '/uploads/ae029388d7b34f9ebcc6789b72b00731.png', '厨房电器', 1, '热销,厨房,便携', 199.00, 239.00, 176, '台', 208, 780, '300ml轻量杯体，6叶刀头，双击启动，杯身可拆洗。未正确安装时无法启动。', 1, 1, NULL, NULL, '2026-05-15 16:33:54', '2026-05-29 14:59:02', NULL, 0, NULL, NULL, NULL);
INSERT INTO `product` VALUES (3, 'YP-AIR-DESK', '桌面空气净化器', '小体积低噪音设计，适合卧室、书桌、办公位和儿童学习桌。', '/uploads/2b21778c5db74fec87ab088595240d6e.png', '健康家居', 2, '空气,桌面,健康', 269.00, 299.00, 118, '台', 77, 980, 'HEPA滤芯，三档风量，USB供电，夜间低亮度指示灯。', 1, 1, NULL, NULL, '2026-05-16 16:33:54', '2026-05-29 14:58:50', NULL, 0, NULL, NULL, NULL);
INSERT INTO `product` VALUES (4, 'YP-LUNCH-2L', '恒温电热饭盒', '双层分区内胆，支持预约加热，适合上班族午餐和学生宿舍使用。', '/uploads/ed46667dcd01406286705f00bda940bf.png', '厨房电器', 1, '饭盒,加热,通勤', 239.00, 279.00, 94, '台', 91, 1100, '304不锈钢内胆，饭菜分区，支持蒸热、保温和防干烧保护。', 1, 1, NULL, NULL, '2026-05-17 16:33:54', '2026-05-29 14:58:34', NULL, 0, NULL, NULL, NULL);
INSERT INTO `product` VALUES (5, 'YP-MITE-MINI', '迷你除螨仪', '高频拍打与热风除湿组合，适合床品、沙发、抱枕和布艺座椅清洁。', '/uploads/c807b8accba248bda6a0a80a7ea0c21a.png', '清洁护理', 3, '除螨,清洁,家居', 329.00, 369.00, 79, '台', 65, 1450, '轻量机身，透明尘杯，支持滤网拆洗。建议每周使用1到2次。', 1, 1, NULL, NULL, '2026-05-18 16:33:54', '2026-05-29 14:58:15', NULL, 0, NULL, NULL, NULL);
INSERT INTO `product` VALUES (6, 'YP-CABLE-BOX', '桌面理线收纳盒', '隐藏插排和杂乱线缆，让办公桌、电视柜和床头柜更整洁。', '/uploads/4cd2d0c15f824261a28028fff116cdae.png', '收纳整理', 4, '收纳,办公,桌面', 59.00, 79.00, 497, '个', 321, 620, '阻燃材质，顶部开槽便于手机充电线穿出，底部留有散热孔。', 1, 1, NULL, NULL, '2026-05-19 16:33:54', '2026-05-29 14:57:45', NULL, 0, NULL, NULL, NULL);
